/// Result of a video export operation.
class VideoExportResult {
  final File file;
  final String filePath;
  final int frameCount;
  final Duration duration;
  final int fileSizeBytes;
  final VideoResolution resolution;
  final VideoExportFormat format;

  VideoExportResult({
    required this.file,
    required this.filePath,
    required this.frameCount,
    required this.duration,
    required this.fileSizeBytes,
    required this.resolution,
    required this.format,
  });

  String get formattedSize {
    if (fileSizeBytes < 1024) return '$fileSizeBytes B';
    if (fileSizeBytes < 1024 * 1024)
      return '${(fileSizeBytes / 1024).toStringAsFixed(1)} KB';
    return '${(fileSizeBytes / 1024 / 1024).toStringAsFixed(1)} MB';
  }
}

/// Replayable frame timeline contract for video animations.
class VideoFrameTimeline {
  const VideoFrameTimeline._();

  /// Returns normalized progress in [0, 1] for a frame sequence.
  ///
  /// A single-frame export is defined as the start of the animation. This keeps
  /// frame interpolation deterministic without dividing by zero.
  static double progress({
    required int frameIndex,
    required int totalFrames,
  }) {
    if (totalFrames <= 0) {
      throw ArgumentError('Invalid totalFrames: $totalFrames');
    }
    if (totalFrames == 1) {
      return 0.0;
    }

    return (frameIndex / (totalFrames - 1)).clamp(0.0, 1.0).toDouble();
  }
}

/// Replayable zoom-factor contract for zoom-in/zoom-out video animations.
///
/// Zoom factors below 1.0 invert the selected animation direction, while
/// zero/non-finite factors produce invalid zooms. Treat malformed factors as a
/// neutral 1.0x movement so stale/custom options cannot poison captured frames.
class VideoZoomFactor {
  static const double neutral = 1.0;

  const VideoZoomFactor._();

  static double normalize(double zoomFactor) {
    if (!zoomFactor.isFinite || zoomFactor < neutral) return neutral;
    return zoomFactor;
  }
}

/// Replayable start-zoom contract for video animation frames.
///
/// Stored or caller-provided views can bypass controller zoom clamps. Normalize
/// at the export-frame boundary so interpolation and pan-orbit radius math never
/// emit NaN/Infinity to the caller's update callback.
class VideoStartZoom {
  static const double neutral = 1.0;

  const VideoStartZoom._();

  static double normalize(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return neutral;
    return zoom;
  }

  static double panOrbitRadius(double zoom) => 0.5 / normalize(zoom);
}

/// Replayable parameter-sweep frame contract for video animations.
///
/// [VideoExportService.calculateParameterFrame] hands updates to an arbitrary
/// caller callback, so malformed sweep configs must be contained here instead
/// of relying on a later controller to reject NaN/Infinity or empty IDs.
class VideoParameterSweepPlan {
  final String parameterId;
  final double startValue;
  final double endValue;
  final double timelineProgress;
  final double sweepProgress;
  final double easedProgress;
  final double value;

  const VideoParameterSweepPlan._({
    required this.parameterId,
    required this.startValue,
    required this.endValue,
    required this.timelineProgress,
    required this.sweepProgress,
    required this.easedProgress,
    required this.value,
  });

  factory VideoParameterSweepPlan.fromSweep({
    required ParameterSweepConfig sweep,
    required AnimationEasing easing,
    required double timelineProgress,
  }) {
    final sweepProgress = sweep.pingPong
        ? timelineProgress < 0.5
            ? timelineProgress * 2
            : 2 - timelineProgress * 2
        : timelineProgress;
    final easedProgress = easing.apply(sweepProgress);
    final value =
        sweep.startValue + (sweep.endValue - sweep.startValue) * easedProgress;

    return VideoParameterSweepPlan._(
      parameterId: sweep.parameterId,
      startValue: sweep.startValue,
      endValue: sweep.endValue,
      timelineProgress: timelineProgress,
      sweepProgress: sweepProgress,
      easedProgress: easedProgress,
      value: value,
    );
  }

  bool get isReplayable {
    return parameterId.isNotEmpty &&
        startValue.isFinite &&
        endValue.isFinite &&
        timelineProgress.isFinite &&
        sweepProgress.isFinite &&
        easedProgress.isFinite &&
        value.isFinite;
  }

  Map<String, double> toUpdates() {
    if (!isReplayable) return const {};
    return {parameterId: value};
  }
}

/// Replayable encoding contract for video exports.
///
/// MP4 is selectable in the public options model, but this Dart-only exporter
/// currently has a GIF encoder. Keep the fallback explicit so output filename,
/// bytes, and reported format cannot silently drift apart.
class VideoExportEncodingPlan {
  final VideoExportFormat requestedFormat;
  final VideoExportFormat effectiveFormat;

  const VideoExportEncodingPlan._({
    required this.requestedFormat,
    required this.effectiveFormat,
  });

  factory VideoExportEncodingPlan.forFormat(
    VideoExportFormat requestedFormat,
  ) {
    return VideoExportEncodingPlan._(
      requestedFormat: requestedFormat,
      effectiveFormat: switch (requestedFormat) {
        VideoExportFormat.gif => VideoExportFormat.gif,
        VideoExportFormat.mp4 => VideoExportFormat.gif,
      },
    );
  }

  bool get usesFallback => requestedFormat != effectiveFormat;

  VideoExportOptions applyTo(VideoExportOptions options) {
    if (options.format == effectiveFormat) return options;
    return options.copyWith(format: effectiveFormat);
  }
}

/// Service for exporting fractal animations as video.
class VideoExportService {
  const VideoExportService();

  /// Returns the format this Dart-only exporter can encode today.
  VideoExportFormat resolveEffectiveFormat(VideoExportFormat requested) {
    return VideoExportEncodingPlan.forFormat(requested).effectiveFormat;
  }

  VideoExportEncodingPlan encodingPlanFor(VideoExportOptions options) {
    return VideoExportEncodingPlan.forFormat(options.format);
  }

  /// Calculate the view state for a given frame in the animation.
  FractalViewState calculateAnimationFrame({
    required FractalViewState startView,
    required VideoExportOptions options,
    required int frameIndex,
    required int totalFrames,
  }) {
    final t = VideoFrameTimeline.progress(
      frameIndex: frameIndex,
      totalFrames: totalFrames,
    );
    final easedT = options.easing.apply(t);
    final startZoom = VideoStartZoom.normalize(startView.zoom);
    final replayableStartView = startZoom == startView.zoom
        ? startView
        : startView.copyWith(zoom: startZoom);

    switch (options.animationType) {
      case VideoAnimationType.zoomIn:
        final zoomFactor = VideoZoomFactor.normalize(options.zoomFactor);
        final targetZoom = startZoom * zoomFactor;
        final newZoom = startZoom + (targetZoom - startZoom) * easedT;
        return replayableStartView.copyWith(zoom: newZoom);

      case VideoAnimationType.zoomOut:
        final zoomFactor = VideoZoomFactor.normalize(options.zoomFactor);
        final targetZoom = startZoom / zoomFactor;
        final newZoom = startZoom + (targetZoom - startZoom) * easedT;
        return replayableStartView.copyWith(zoom: newZoom);

      case VideoAnimationType.rotate:
        final angle = easedT * 2 * math.pi;
        final currentRot = replayableStartView.rotation;
        return replayableStartView.copyWith(
          rotation: Vector3(currentRot.x, currentRot.y + angle, currentRot.z),
        );

      case VideoAnimationType.pan:
        final angle = easedT * 2 * math.pi;
        final radius = VideoStartZoom.panOrbitRadius(startView.zoom);
        return replayableStartView.copyWith(
          pan: Vector2(
            replayableStartView.pan.x + radius * math.cos(angle),
            replayableStartView.pan.y + radius * math.sin(angle),
          ),
        );

      case VideoAnimationType.parameterSweep:
      case VideoAnimationType.custom:
        return replayableStartView;
    }
  }

  /// Calculate parameter values for a parameter sweep animation.
  Map<String, double> calculateParameterFrame({
    required Map<String, Object> startParams,
    required VideoExportOptions options,
    required int frameIndex,
    required int totalFrames,
  }) {
    final sweep = options.parameterSweep;
    if (sweep == null) return {};

    final timelineProgress = VideoFrameTimeline.progress(
      frameIndex: frameIndex,
      totalFrames: totalFrames,
    );
    final plan = VideoParameterSweepPlan.fromSweep(
      sweep: sweep,
      easing: options.easing,
      timelineProgress: timelineProgress,
    );

    return plan.toUpdates();
  }

  /// Generate a unique filename for the export.
  String generateFilename(VideoExportOptions options) {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    return 'fractal_${options.animationType.name}_$timestamp.${options.format.extension}';
  }

  /// Capture a widget as PNG bytes.
  Future<Uint8List> captureWidget(GlobalKey boundaryKey,
      {double pixelRatio = 2.0}) async {
    final boundary = boundaryKey.currentContext?.findRenderObject()
        as RenderRepaintBoundary?;
    if (boundary == null) {
      throw Exception('Could not find render boundary');
    }

    final image = await boundary.toImage(pixelRatio: pixelRatio);
    final byteData = await image.toByteData(format: ui.ImageByteFormat.png);
    if (byteData == null) {
      throw Exception('Could not capture image');
    }

    return byteData.buffer.asUint8List();
  }

  /// Export video with the given options.
  ///
  /// This method captures frames and encodes them. For full video encoding,
  /// use a native plugin or FFmpeg.
  Future<VideoExportResult> exportVideo({
    required VideoExportOptions options,
    required FractalViewState startView,
    required Map<String, Object> startParams,
    required String fractalType,
    required void Function(
            FractalViewState view, Map<String, double>? paramUpdates)
        updateView,
    required Future<Uint8List> Function() captureFrame,
    void Function(double progress, String status)? onProgress,
  }) async {
    if (kIsWeb) throw UnsupportedError('exportVideo is not supported on web');
    final encodingPlan = encodingPlanFor(options);
    final effectiveOptions = encodingPlan.applyTo(options);
    final totalFrames = options.totalFrames;

    // Capture and decode frames incrementally to avoid RAM exhaustion
    final decodedFrames = <img.Image>[];

    for (var i = 0; i < totalFrames; i++) {
      // Calculate view for this frame
      final view = calculateAnimationFrame(
        startView: startView,
        options: options,
        frameIndex: i,
        totalFrames: totalFrames,
      );

      // Calculate parameter updates if doing a sweep
      Map<String, double>? paramUpdates;
      if (options.animationType == VideoAnimationType.parameterSweep) {
        paramUpdates = calculateParameterFrame(
          startParams: startParams,
          options: options,
          frameIndex: i,
          totalFrames: totalFrames,
        );
      }

      // Update the fractal
      updateView(view, paramUpdates);

      // Wait for render
      await Future.delayed(const Duration(milliseconds: 16));

      // Capture frame
      final frameBytes = await captureFrame();

      // Decode immediately and release raw bytes
      final decoded = img.decodePng(frameBytes);
      if (decoded == null) {
        throw Exception('Failed to decode frame $i');
      }
      decodedFrames.add(decoded);

      // Report progress
      final progress = (i + 1) / totalFrames;
      onProgress?.call(progress, 'Rendering frame ${i + 1} of $totalFrames');
    }

    final bytes = _encodeFrames(decodedFrames, encodingPlan.effectiveFormat);

    // Save to file
    final dir = await getTemporaryDirectory();
    final filename = generateFilename(effectiveOptions);
    final outputPath = '${dir.path}/$filename';
    final outputFile = File(outputPath);
    await outputFile.writeAsBytes(bytes);

    final size = await outputFile.length();

    return VideoExportResult(
      file: outputFile,
      filePath: outputFile.path,
      frameCount: decodedFrames.length,
      duration: options.duration,
      fileSizeBytes: size,
      resolution: options.resolution,
      format: encodingPlan.effectiveFormat,
    );
  }

  Uint8List _encodeFrames(
    List<img.Image> decodedFrames,
    VideoExportFormat effectiveFormat,
  ) {
    if (decodedFrames.isEmpty) {
      throw StateError('Cannot encode video export without frames');
    }

    switch (effectiveFormat) {
      case VideoExportFormat.gif:
        final firstFrame = decodedFrames.first;
        for (var i = 1; i < decodedFrames.length; i++) {
          firstFrame.addFrame(decodedFrames[i]);
        }
        return Uint8List.fromList(img.encodeGif(firstFrame));
      case VideoExportFormat.mp4:
        throw UnsupportedError('MP4 encoding is not available');
    }
  }
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

/// Provenance for the custom export dimension that wins resolution.
enum CustomExportDimensionSource {
  fieldText,
  currentValue,
  fallback,
}

/// Replayable result of resolving one custom export dimension.
///
/// The export model clamps target dimensions later, but the sheet summary and
/// submission payload read [ExportOptions.customWidth]/customHeight directly.
/// Keep that boundary normalized too so all export dimension paths share the
/// same safety contract.
final class CustomExportDimensionResolution {
  const CustomExportDimensionResolution({
    required this.value,
    required this.source,
    required this.wasClamped,
  });

  final int value;
  final CustomExportDimensionSource source;
  final bool wasClamped;
}

CustomExportDimensionResolution resolveCustomExportDimensionPlan({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  return _normalizeCustomExportDimension(
        parsed,
        source: CustomExportDimensionSource.fieldText,
      ) ??
      _normalizeCustomExportDimension(
        currentValue,
        source: CustomExportDimensionSource.currentValue,
      ) ??
      _normalizeFallbackCustomExportDimension(fallback);
}

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  return resolveCustomExportDimensionPlan(
    fieldText: fieldText,
    currentValue: currentValue,
    fallback: fallback,
  ).value;
}

CustomExportDimensionResolution? _normalizeCustomExportDimension(
  int? value, {
  required CustomExportDimensionSource source,
}) {
  final normalized = ExportDimensionPolicy.positiveCustomDimension(value);
  if (normalized == null) return null;

  return CustomExportDimensionResolution(
    value: normalized,
    source: source,
    wasClamped: normalized != value,
  );
}

CustomExportDimensionResolution _normalizeFallbackCustomExportDimension(
  int fallback,
) {
  final safeFallback = fallback > 0 ? fallback : 1;
  final normalized = ExportDimensionPolicy.positiveCustomDimension(
    safeFallback,
  )!;

  return CustomExportDimensionResolution(
    value: normalized,
    source: CustomExportDimensionSource.fallback,
    wasClamped: normalized != fallback,
  );
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/builders/built_in_preset_contract.dart';
import 'package:flutter_fractals/core/modules/builders/uniform_layout.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 2D escape-time fractal.
///
/// Adding a new escape-time fractal = one [EscapeTimeConfig] + one .frag shader.
/// No Dart module file needed.
class EscapeTimeConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final double defaultIterations;
  final double defaultBailout;
  final int defaultColorScheme;
  final double defaultCenterX;
  final double defaultCenterY;
  final double defaultZoom;
  final int maxIterations;
  final String category;
  final List<FractalParameter> extraParams;
  final List<FractalPreset> extraPresets;

  const EscapeTimeConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.defaultIterations = 120,
    this.defaultBailout = 4.0,
    this.defaultColorScheme = 0,
    this.defaultCenterX = 0.0,
    this.defaultCenterY = 0.0,
    this.defaultZoom = 1.0,
    // Most runtime_effect escape-time shaders compile with a static loop cap of 500.
    // Keep the UI/params cap aligned with shader reality to avoid misleading controls.
    this.maxIterations = 500,
    this.category = 'Escape-Time',
    this.extraParams = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [EscapeTimeConfig].
///
/// All standard escape-time fractals share the same uniform layout:
///   float 0: uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uCenter (vec2)
///   float 5: uZoom
///   float 6: uIterations
///   float 7: uBailout
///   float 8: uColorScheme
///   float 9: uTransparentBg
///   float 10+: extra params (in order)
///
/// This eliminates per-fractal Dart boilerplate.
FractalModule buildEscapeTimeModule(EscapeTimeConfig config) {
  assert(
    config.extraParams.every((p) => p.defaultValue is num),
    'Escape-time extra parameters must have numeric defaults because they are written to float uniforms.',
  );

  final defaults = _resolveEscapeTimeDefaults(config);

  final parameters = [
    CommonFractalParams.iterations(
      defaultValue: defaults.iterations,
      max: config.maxIterations,
    ),
    CommonFractalParams.bailout(defaultValue: config.defaultBailout),
    CommonFractalParams.colorScheme64(defaultValue: config.defaultColorScheme),
    ...config.extraParams,
  ];

  final defaultParams = <String, Object>{
    'iterations': defaults.iterations,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
  };
  for (final p in config.extraParams) {
    defaultParams[p.id] = p.defaultValue;
  }

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2(defaults.centerX, defaults.centerY),
      zoom: defaults.zoom,
      rotation: Vector3.zero(),
    ),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.twoD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: buildBuiltInPresetList(
      moduleId: config.id,
      defaultPreset: defaultPreset,
      extraPresets: config.extraPresets,
    ),
    setUniforms: (shader, state, size, time) {
      shader.setFloat(EscapeTimeUniformSlots.time, time);
      shader.setFloat(EscapeTimeUniformSlots.resolutionX, size.width);
      shader.setFloat(EscapeTimeUniformSlots.resolutionY, size.height);
      shader.setFloat(EscapeTimeUniformSlots.centerX, state.view.pan.x);
      shader.setFloat(EscapeTimeUniformSlots.centerY, state.view.pan.y);
      shader.setFloat(EscapeTimeUniformSlots.zoom, state.view.zoom);
      shader.setFloat(EscapeTimeUniformSlots.iterations,
          readDouble(state.params, 'iterations', defaults.iterations));
      shader.setFloat(EscapeTimeUniformSlots.bailout,
          readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          EscapeTimeUniformSlots.colorScheme,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(EscapeTimeUniformSlots.transparentBackground,
          state.transparentBackground ? 1.0 : 0.0);
      for (int i = 0; i < config.extraParams.length; i++) {
        final p = config.extraParams[i];
        shader.setFloat(EscapeTimeUniformSlots.extraStart + i,
            readDouble(state.params, p.id, (p.defaultValue as num).toDouble()));
      }
    },
  );
}

class _EscapeTimeDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _EscapeTimeDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_EscapeTimeDefaults _resolveEscapeTimeDefaults(EscapeTimeConfig config) {
  var effectiveIterations = config.defaultIterations;
  var effectiveCenterX = config.defaultCenterX;
  var effectiveCenterY = config.defaultCenterY;
  var effectiveZoom = config.defaultZoom;

  if (config.extraPresets.isNotEmpty) {
    // If the module has curated presets, use the first curated preset as
    // default framing/iterations so each fractal starts with a distinctive
    // initial state instead of generic (0,0,1,120).
    final curated = config.extraPresets.first;
    final it = curated.params['iterations'];
    if (it is num) {
      effectiveIterations = it.toDouble();
    }
    // Only use first preset's view if no explicit center/zoom was configured.
    final hasExplicitView = config.defaultCenterX != 0.0 ||
        config.defaultCenterY != 0.0 ||
        config.defaultZoom != 1.0;
    if (!hasExplicitView) {
      effectiveCenterX = curated.view.pan.x;
      effectiveCenterY = curated.view.pan.y;
      effectiveZoom = curated.view.zoom;
    }
  } else {
    // For modules that still use baseline constructor defaults, generate
    // deterministic per-module defaults from the module id.
    final autoDefaults = _autoDefaultsForModule(config.id);
    final usesBaseIterations = config.defaultIterations == 120;
    final usesBaseCenter =
        config.defaultCenterX == 0.0 && config.defaultCenterY == 0.0;
    final usesBaseZoom = config.defaultZoom == 1.0;

    if (usesBaseIterations) {
      effectiveIterations = autoDefaults.iterations;
    }
    if (usesBaseCenter) {
      effectiveCenterX = autoDefaults.centerX;
      effectiveCenterY = autoDefaults.centerY;
    }
    if (usesBaseZoom) {
      effectiveZoom = autoDefaults.zoom;
    }
  }

  return _EscapeTimeDefaults(
    centerX: effectiveCenterX,
    centerY: effectiveCenterY,
    zoom: effectiveZoom.clamp(0.2, 32.0),
    iterations:
        effectiveIterations.clamp(20.0, config.maxIterations.toDouble()),
  );
}

class _AutoModuleDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _AutoModuleDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_AutoModuleDefaults _autoDefaultsForModule(String moduleId) {
  final hash = _fnv1a32(moduleId);

  double unit(int shift) => ((hash >> shift) & 0xFF) / 255.0;

  // Keep defaults stable but non-generic per module:
  // - center around the classic Mandelbrot neighborhood
  // - moderate zoom that still shows structure
  // - varied iteration density for immediate detail diversity
  final centerX = -0.55 + (unit(0) - 0.5) * 0.5; // [-0.80, -0.30]
  final centerY = (unit(8) - 0.5) * 0.4; // [-0.20, 0.20]
  final zoom = 0.65 + unit(16) * 0.9; // [0.65, 1.55]
  final iterations = 110.0 + (hash % 131); // [110, 240]

  return _AutoModuleDefaults(
    centerX: centerX,
    centerY: centerY,
    zoom: zoom,
    iterations: iterations,
  );
}

int _fnv1a32(String text) {
  var hash = 0x811C9DC5;
  for (final codeUnit in text.codeUnits) {
    hash ^= codeUnit;
    hash = (hash * 0x01000193) & 0xFFFFFFFF;
  }
  return hash;
}

/// Uniform slot contracts shared by declarative module builders.
///
/// Keep these indices aligned with the matching fragment shaders. Centralizing
/// them makes shader/builder drift visible during review instead of burying the
/// contract as repeated magic numbers in setUniforms closures.
abstract final class EscapeTimeUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int centerX = 3;
  static const int centerY = 4;
  static const int zoom = 5;
  static const int iterations = 6;
  static const int bailout = 7;
  static const int colorScheme = 8;
  static const int transparentBackground = 9;
  static const int extraStart = 10;
}

abstract final class Raymarched3DUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int mouseX = 3;
  static const int mouseY = 4;
  static const int zoom = 5;
  static const int rotationX = 6;
  static const int rotationY = 7;
  static const int rotationZ = 8;
  static const int power = 9;
  static const int iterations = 10;
  static const int steps = 11;
  static const int bailout = 12;
  static const int colorScheme = 13;
  static const int fractalType = 14;
  static const int transparentBackground = 15;
}

abstract final class MandelbrotDf2UniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int centerHiX = 3;
  static const int centerLoX = 4;
  static const int centerHiY = 5;
  static const int centerLoY = 6;
  static const int zoom = 7;
  static const int iterations = 8;
  static const int bailout = 9;
  static const int colorScheme = 10;
  static const int transparentBackground = 11;
}

/// Replayable duplicate-ID report for declarative module catalogs.
///
/// Module registries may defensively de-duplicate IDs, but catalog sources
/// should expose collisions before candidates are silently dropped. Keeping the
/// first index and duplicate indexes together makes ingestion/order bugs
/// reproducible from the raw catalog list alone.
typedef CatalogIdOf<T> = String Function(T entry);

final class CatalogIdCollision<T> {
  CatalogIdCollision({
    required this.id,
    required this.firstIndex,
    required Iterable<int> duplicateIndexes,
    required Iterable<T> entries,
  })  : duplicateIndexes = List.unmodifiable(duplicateIndexes),
        entries = List.unmodifiable(entries) {
    assert(this.duplicateIndexes.isNotEmpty, 'collision requires duplicates');
    assert(this.entries.length == this.duplicateIndexes.length + 1,
        'entries must contain first entry plus duplicates');
  }

  final String id;
  final int firstIndex;
  final List<int> duplicateIndexes;
  final List<T> entries;

  List<int> get indexes => List.unmodifiable([
        firstIndex,
        ...duplicateIndexes,
      ]);

  /// Number of later candidates that a first-wins de-duplication pass drops.
  int get droppedCandidateCount => duplicateIndexes.length;
}

List<CatalogIdCollision<T>> findCatalogIdCollisions<T>(
  Iterable<T> entries,
  CatalogIdOf<T> idOf,
) {
  final indexesById = <String, List<int>>{};
  final entriesById = <String, List<T>>{};

  var index = 0;
  for (final entry in entries) {
    final id = idOf(entry);
    indexesById.putIfAbsent(id, () => <int>[]).add(index);
    entriesById.putIfAbsent(id, () => <T>[]).add(entry);
    index++;
  }

  return [
    for (final collision in indexesById.entries)
      if (collision.value.length > 1)
        CatalogIdCollision<T>(
          id: collision.key,
          firstIndex: collision.value.first,
          duplicateIndexes: collision.value.skip(1),
          entries: entriesById[collision.key]!,
        ),
  ];
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_builder.dart';

void main() {
  group('buildEscapeTimeModule', () {
    test('built-in generated presets are replayable', () {
      const config = EscapeTimeConfig(
        id: 'replayable-test',
        name: 'Replayable Test',
        shaderAsset: 'shaders/replayable_test.frag',
      );

      final first = buildEscapeTimeModule(config);
      final second = buildEscapeTimeModule(config);

      expect(first.defaultPreset.createdAt, DateTime.utc(2025, 1, 1));
      expect(second.defaultPreset.createdAt, first.defaultPreset.createdAt);
      expect(
        first.builtInPresets.map((preset) => preset.createdAt),
        everyElement(first.defaultPreset.createdAt),
      );
      expect(
        first.builtInPresets.map((preset) => preset.isBuiltIn),
        everyElement(isTrue),
      );
    });

    test('curated extra presets are normalized as replayable built-ins', () {
      final config = EscapeTimeConfig(
        id: 'curated-test',
        name: 'Curated Test',
        shaderAsset: 'shaders/curated_test.frag',
        extraPresets: [
          FractalPreset(
            id: 'curated-test-interesting',
            moduleId: 'curated-test',
            name: 'Interesting',
            params: const {'iterations': 240, 'bailout': 4.0},
            view: FractalViewState(
              pan: Vector2(-0.75, 0.1),
              zoom: 8.0,
              rotation: Vector3.zero(),
            ),
            createdAt: DateTime.now(),
          ),
        ],
      );

      final module = buildEscapeTimeModule(config);
      final curated = module.builtInPresets.singleWhere(
        (preset) => preset.id == 'curated-test-interesting',
      );

      expect(curated.isBuiltIn, isTrue);
      expect(curated.createdAt, DateTime.utc(2025, 1, 1));
      expect(curated.params['iterations'], 240);
      expect(curated.view.zoom, 8.0);
    });

    test('curated extra preset moduleIds are normalized to module id', () {
      final config = EscapeTimeConfig(
        id: 'module-id-test',
        name: 'Module Id Test',
        shaderAsset: 'shaders/module_id_test.frag',
        extraPresets: [
          FractalPreset(
            id: 'module-id-test-interesting',
            moduleId: 'stale-module-id',
            name: 'Interesting',
            params: const {'iterations': 240, 'bailout': 4.0},
            view: FractalViewState(
              pan: Vector2(-0.75, 0.1),
              zoom: 8.0,
              rotation: Vector3.zero(),
            ),
            createdAt: DateTime.now(),
          ),
        ],
      );

      final module = buildEscapeTimeModule(config);

      expect(
        module.builtInPresets.map((preset) => preset.moduleId),
        everyElement('module-id-test'),
      );
    });

    test('curated preset ids cannot collide with generated classic ids', () {
      final config = EscapeTimeConfig(
        id: 'collision-test',
        name: 'Collision Test',
        shaderAsset: 'shaders/collision_test.frag',
        extraPresets: [
          FractalPreset(
            id: 'collision-test-classic',
            moduleId: 'collision-test',
            name: 'Curated Classic',
            params: const {'iterations': 240, 'bailout': 4.0},
            view: FractalViewState(
              pan: Vector2(-0.75, 0.1),
              zoom: 8.0,
              rotation: Vector3.zero(),
            ),
            createdAt: DateTime.now(),
          ),
        ],
      );

      final module = buildEscapeTimeModule(config);
      final ids = module.builtInPresets.map((preset) => preset.id).toList();

      expect(ids, ['collision-test-classic', 'collision-test-classic-2']);
      expect(ids.toSet(), hasLength(ids.length));
      expect(module.builtInPresets.last.name, 'Curated Classic');
    });
  });
}

