import 'package:flutter_fractals/core/models/fractal_preset.dart';

/// Stable provenance marker for generated built-in presets.
///
/// Builder-owned presets are part of the app catalog, not user-created data, so
/// their metadata must be replayable across registry rebuilds and test runs.
final builtInPresetCreatedAt = DateTime.utc(2025, 1, 1);

/// Returns the builder-facing built-in preset list with replayable metadata.
///
/// Catalog entries often provide curated [extraPresets] for params/view only.
/// Normalize them here so callers cannot accidentally surface mutable-looking,
/// non-replayable, or stale-module presets in [FractalModule.builtInPresets].
List<FractalPreset> buildBuiltInPresetList({
  required String moduleId,
  required FractalPreset defaultPreset,
  required List<FractalPreset> extraPresets,
}) {
  assert(moduleId.isNotEmpty, 'Built-in presets require a module id.');
  assert(
    defaultPreset.moduleId == moduleId,
    'Default built-in preset moduleId must match its module.',
  );

  final usedIds = <String>{};
  return [
    _asReplayableBuiltInPreset(
      defaultPreset.copyWith(id: '$moduleId-classic', name: 'Classic'),
      moduleId,
      usedIds,
    ),
    ...extraPresets.map((preset) => _asReplayableBuiltInPreset(
          preset,
          moduleId,
          usedIds,
        )),
  ];
}

FractalPreset _asReplayableBuiltInPreset(
  FractalPreset preset,
  String moduleId,
  Set<String> usedIds,
) {
  return preset.copyWith(
    id: _uniquePresetId(preset.id, usedIds),
    moduleId: moduleId,
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );
}

String _uniquePresetId(String id, Set<String> usedIds) {
  if (usedIds.add(id)) return id;

  var suffix = 2;
  while (true) {
    final candidate = '$id-$suffix';
    if (usedIds.add(candidate)) return candidate;
    suffix++;
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/gpu_gradient_module.dart';
import 'package:flutter_fractals/core/modules/gpu_sampler_diag_module.dart';
import 'package:flutter_fractals/core/modules/hydrogen_orbital_module.dart';
import 'package:flutter_fractals/core/modules/julia_dual_module.dart';
import 'package:flutter_fractals/core/modules/julia_module.dart';
import 'package:flutter_fractals/core/modules/mandelbox_module.dart';
import 'package:flutter_fractals/core/modules/mandelbulb_module.dart';
import 'package:flutter_fractals/core/modules/nova_module.dart';
import 'package:flutter_fractals/core/modules/phoenix_module.dart';
import 'package:flutter_fractals/core/modules/test_shaders_module.dart';

/// Registry of all available fractal modules.
///
/// ## Architecture (post-refactor)
///
/// Most 2D escape-time fractals are built **declaratively** from
/// [EscapeTimeConfig] entries in `builders/escape_time/catalog.dart`.
/// Adding a new escape-time fractal = one config entry + one .frag shader.
///
/// Fractals with **custom parameters** (Julia seeds, Phoenix p/q, 3D rotation)
/// still use dedicated builder functions.
///
/// ## How to add a new fractal
///
/// **Standard escape-time (iterations + bailout + color):**
/// 1. Write shader following standard uniform layout (see builders/escape_time/builder.dart)
/// 2. Add `EscapeTimeConfig(...)` to `builders/escape_time/catalog.dart`
/// 3. Register shader in `pubspec.yaml`
/// 4. Done!
///
/// **Custom params or non-escape-time:**
/// 1. Create a `buildXxxModule()` function
/// 2. Add it to [_customModules] below
///
/// {@category Modules}
class ModuleRegistry {
  /// All available fractal modules (built lazily on first access).
  late final List<FractalModule> modules = _buildAll();

  /// Creates the registry.
  ModuleRegistry();

  /// Look up a module by [id]. Throws if not found.
  FractalModule byId(String id) {
    return modules.firstWhere((m) => m.id == id);
  }

  static List<FractalModule> _buildAll() {
    // IDs already in the escape-time catalog (built declaratively).
    // Defensive de-duplication keeps registry stable even if the catalog
    // accidentally contains repeated ids.
    final catalogModules = _dedupeById(buildEscapeTimeCatalogModules());
    final catalogIds = catalogModules.map((m) => m.id).toSet();

    // Custom modules with special params/uniforms
    final customModules = <FractalModule>[
      // Julia needs extra seed params (cx, cy)
      if (!catalogIds.contains('julia')) buildJuliaModule(),
      // Julia Dual: side-by-side Mandelbrot + Julia viewer
      if (!catalogIds.contains('julia_dual')) buildJuliaDualModule(),
      // Phoenix needs extra (p, q) params
      if (!catalogIds.contains('phoenix')) buildPhoenixModule(),
      // Nova needs relaxation param instead of bailout
      if (!catalogIds.contains('nova')) buildNovaModule(),
      // Mandelbulb is 3D with rotation uniforms
      if (!catalogIds.contains('mandelbulb')) buildMandelbulbModule(),
      // Mandelbox is 3D with box-fold + sphere-fold DE
      if (!catalogIds.contains('mandelbox')) buildMandelboxModule(),
      // Hydrogen orbital is a volumetric density renderer with custom controls.
      if (!catalogIds.contains('hydrogen_orbital'))
        buildHydrogenOrbitalModule(),
    ];

    // Diagnostics (debug only, always last)
    final diagModules = kDebugMode
        ? [
            testAlwaysRedModule,
            testUniformOnlyModule,
            testMinimalModule,
            testGlFragCoordModule,
            testFlutterCoordModule,
            buildGpuGradientModule(),
            buildGpuSamplerDiagModule(),
          ]
        : <FractalModule>[];

    // Merge: catalog first (Mandelbrot at top), then custom, then diag.
    // Insert Julia after Mandelbrot, Phoenix after Burning Ship for UX order.
    final result = <FractalModule>[];

    // Find key positions for insertion
    final mandelbrotIdx =
        catalogModules.indexWhere((m) => m.id == 'mandelbrot');
    final burningShipIdx =
        catalogModules.indexWhere((m) => m.id == 'burning_ship');
    final novaJuliaIdx = catalogModules.indexWhere((m) => m.id == 'nova_julia');

    for (int i = 0; i < catalogModules.length; i++) {
      // Insert Nova right before Nova Julia
      if (i == novaJuliaIdx) {
        final nova = customModules.where((m) => m.id == 'nova');
        result.addAll(nova);
      }
      result.add(catalogModules[i]);
      // Insert Julia and Julia Dual right after Mandelbrot
      if (i == mandelbrotIdx) {
        final julia = customModules.where((m) => m.id == 'julia');
        result.addAll(julia);
        final juliaDual = customModules.where((m) => m.id == 'julia_dual');
        result.addAll(juliaDual);
      }
      // Insert Phoenix right after Burning Ship
      if (i == burningShipIdx) {
        final phoenix = customModules.where((m) => m.id == 'phoenix');
        result.addAll(phoenix);
      }
    }

    // Add remaining custom modules not yet inserted
    for (final m in customModules) {
      if (!result.any((r) => r.id == m.id)) {
        result.add(m);
      }
    }

    // 3D ray-marched catalog modules (KIFS, Quaternion, exotic)
    final raymarched3DModules = buildRaymarched3DCatalogModules();
    result.addAll(raymarched3DModules);

    result.addAll(diagModules);
    // Keep later modules when ids collide so purpose-built 3D catalog entries
    // can replace older placeholder escape-time variants with the same id.
    return _dedupeById(result, preferLast: true);
  }

  static List<FractalModule> _dedupeById(
    List<FractalModule> modules, {
    bool preferLast = false,
  }) {
    if (preferLast) {
      final seen = <String>{};
      final reversedUnique = <FractalModule>[];
      for (final module in modules.reversed) {
        if (seen.add(module.id)) {
          reversedUnique.add(module);
        }
      }
      return reversedUnique.reversed.toList(growable: false);
    }

    final seen = <String>{};
    final unique = <FractalModule>[];
    for (final module in modules) {
      if (seen.add(module.id)) {
        unique.add(module);
      }
    }
    return unique;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/builders/catalog_id_collisions.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_builder.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';

/// Catalog ID integrity tests (P0 #4).
///
/// These tests act as a lock on the catalog — any accidental rename,
/// removal, or duplication of a catalog ID will be caught here.
///
/// ## Expected counts (update when catalog intentionally grows)
///
/// - Escape-time catalog raw unique IDs       : 488
/// - Raymarched-3D catalog unique IDs         :  10
/// - Custom hand-built modules                :   7
///   (julia, julia_dual, phoenix, nova, mandelbulb, mandelbox,
///    hydrogen_orbital)
/// - Total ModuleRegistry modules (non-debug) : 506
///
/// The "196 GPU shaders" figure in TODO.md refers to fragment shader
/// assets compiled at build time; it predates the full catalog expansion.
void main() {
  // ---------------------------------------------------------------------------
  // 1. Escape-time catalog — raw entries
  // ---------------------------------------------------------------------------
  group('EscapeTimeConfig catalog entries', () {
    late final List<EscapeTimeConfig> catalog;

    setUpAll(() {
      catalog = escapeTimeCatalog;
    });

    test('total entry count is 488', () {
      expect(catalog.length, 488,
          reason: 'Update this constant when new entries are intentionally '
              'added to escape_time_catalog.dart.');
    });

    test('all IDs match pattern: lowercase alphanumeric + underscores', () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = catalog
          .map((c) => c.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty,
          reason: 'IDs must be lowercase alphanumeric + underscores. '
              'Bad IDs: $bad');
    });

    test('all IDs are unique before registry de-duplication', () {
      final collisions = findCatalogIdCollisions(catalog, (c) => c.id);
      final collisionSummary = collisions
          .map((c) => '${c.id}@${c.indexes.join(',')}')
          .toList(growable: false);

      expect(
        collisionSummary,
        isEmpty,
        reason: 'Duplicate raw catalog IDs are silently dropped before '
            'ModuleRegistry exposes modules.',
      );
    });

    test('no catalog entry has an empty name', () {
      final empty = catalog.where((c) => c.name.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must have a non-empty name.');
    });

    test('no catalog entry has an empty shader asset path', () {
      final empty = catalog.where((c) => c.shaderAsset.trim().isEmpty).toList();
      expect(empty.map((c) => c.id).toList(), isEmpty,
          reason: 'Every catalog entry must declare a shaderAsset path.');
    });

    // Snapshot test: any rename/removal/addition will fail here.
    // Update this list when intentionally changing catalog IDs.
    test('snapshot — first 20 catalog IDs are stable', () {
      final expected = [
        'mandelbrot',
        'burning_ship',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'nova_julia',
        'fatou',
        'gamma_fractal',
        'perpendicular_mandelbrot',
        'lambda',
        'magnet_type_1',
        'magnet_type_2',
        'magnet_type_3',
        'power_sum',
        'cactus',
        'astroid',
        'deltoid',
        'eisenstein',
        'druid',
      ];
      final actual = catalog.take(20).map((c) => c.id).toList();
      expect(actual, expected,
          reason: 'First-20 catalog IDs changed. '
              'If intentional, update this snapshot.');
    });
  });

  // ---------------------------------------------------------------------------
  // 2. ModuleRegistry — built registry (release mode, no debug modules)
  // ---------------------------------------------------------------------------
  group('ModuleRegistry integrity', () {
    late final ModuleRegistry registry;

    setUpAll(() {
      registry = ModuleRegistry();
    });

    test('total module count is 506 (non-debug)', () {
      // Debug-only diagnostic modules are excluded in release/test builds
      // because kDebugMode is false in test environments.
      expect(registry.modules.length, 506,
          reason: 'Update this constant when new modules are intentionally '
              'added to the de-duplicated registry.');
    });

    test('all module IDs are unique (no duplicates)', () {
      final ids = registry.modules.map((m) => m.id).toList();
      final seen = <String>{};
      final dupes = <String>[];
      for (final id in ids) {
        if (!seen.add(id)) dupes.add(id);
      }
      expect(dupes, isEmpty,
          reason: 'Duplicate module IDs detected: $dupes. '
              'The registry deduplicates, but duplicates in the raw catalog '
              'waste entries.');
    });

    test('all module IDs match pattern: lowercase alphanumeric + underscores',
        () {
      final pattern = RegExp(r'^[a-z0-9_]+$');
      final bad = registry.modules
          .map((m) => m.id)
          .where((id) => !pattern.hasMatch(id))
          .toList();
      expect(bad, isEmpty, reason: 'Non-conforming module IDs: $bad');
    });

    test('no module has an empty shader asset path', () {
      final empty = registry.modules
          .where((m) => m.shaderAsset.trim().isEmpty)
          .map((m) => m.id)
          .toList();
      expect(empty, isEmpty,
          reason: 'Every module must declare a non-empty shaderAsset. '
              'Missing: $empty');
    });

    test('byId lookup succeeds for mandelbrot', () {
      expect(() => registry.byId('mandelbrot'), returnsNormally);
      expect(registry.byId('mandelbrot').id, 'mandelbrot');
    });

    test('byId lookup succeeds for all custom hand-built modules', () {
      const customIds = [
        'julia',
        'julia_dual',
        'phoenix',
        'nova',
        'mandelbulb',
        'mandelbox',
        'hydrogen_orbital',
      ];
      for (final id in customIds) {
        expect(
          () => registry.byId(id),
          returnsNormally,
          reason: 'Custom module "$id" not found in registry.',
        );
      }
    });

    // Snapshot of known-stable IDs. Removing or renaming any of these will
    // fail this test, prompting an intentional update.
    test('snapshot — known stable module IDs are present', () {
      const knownIds = [
        'mandelbrot',
        'julia',
        'julia_dual',
        'burning_ship',
        'phoenix',
        'nova',
        'nova_julia',
        'tricorn',
        'celtic',
        'buffalo',
        'multibrot3',
        'mandelbulb',
        'mandelbox',
        'hydrogen_orbital',
        'kifs_menger',
        'kifs_sierpinski_tetra',
        'quaternion_julia_3d',
      ];
      final registryIds = registry.modules.map((m) => m.id).toSet();
      final missing = knownIds.where((id) => !registryIds.contains(id));
      expect(missing, isEmpty,
          reason: 'Previously-present module IDs are missing: $missing. '
              'If intentional, update this snapshot.');
    });
  });
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

