@pragma('vm:prefer-inline')
(double x, double y) _cdivSafe(double ax, double ay, double bx, double by) {
  final d = math.max(1e-20, bx * bx + by * by);
  return ((ax * bx + ay * by) / d, (ay * bx - ax * by) / d);
