@pragma('vm:prefer-inline')
(double x, double y) _clogSafe(double ax, double ay) {
  final r2 = math.max(1e-20, ax * ax + ay * ay);
  return (0.5 * math.log(r2), math.atan2(ay, ax));
}

@pragma('vm:prefer-inline')
